// package-lock.json generation script
const fs = require('fs');
const path = require('path');

function generatePackageLock() {
  const packageJsonPath = path.join(__dirname, 'package.json');
  const packageLockPath = path.join(__dirname, 'package-lock.json');

  if (fs.existsSync(packageLockPath)) {
    console.log('package-lock.json already exists. Skipping generation.');
    return;
  }

  try {
    const packageData = require(packageJsonPath);
    fs.writeFileSync(
      packageLockPath,
      JSON.stringify({ devDependencies: {}, dependencies: packageData.dependencies }, null, 2)
    );
    console.log('Generated package-lock.json successfully.');
  } catch (error) {
    console.error('Error generating package-lock.json:', error);
  }
}

// Usage
generatePackageLock();